def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""

    def clean_subject(subject: str) -> str:
        """Remove '(comicsCharacter)' suffix from subject names."""
        return subject.replace(" (comicsCharacter)", "").replace("(comicsCharacter)", "")

    def clean_object(obj: str) -> str:
        """Remove surrounding quotes from object values."""
        if obj and ((obj.startswith('"') and obj.endswith('"')) or (obj.startswith("'") and obj.endswith("'"))):
            return obj[1:-1]
        return obj

    # Group triples by subject for complex sentence building
    subject_triples = {}
    for t in triples:
        subject = clean_subject(t.subject)
        if subject not in subject_triples:
            subject_triples[subject] = []
        subject_triples[subject].append((t.predicate, clean_object(t.object)))

    # Mapping predicates to phrase generators with better grammar
    def alt_name(s, o): return f"also known as {o}"
    def creator(s, o): return f"was created by {o}"
    def full_name(s, o): return f"whose full name is {o}"
    def founded_by(s, o): return f"was founded by {o}"
    def key_person(s, o): return f"with {o} as a key person"
    def city(s, o): return f"located in {o}"
    def product(s, o): return f"produces {o}"
    def last_aired(s, o): return f"last aired on {o}"
    def starring(s, o): return f"stars {o}"
    def first_appearance(s, o): return f"first appeared in the film {o}"
    def voice(s, o): return f"voiced by {o}"
    def distributor(s, o): return f"distributed by {o}"
    def birth_place(s, o): return f"was born in {o}"
    def nationality(s, o):
        # Handle nationality more naturally
        o_lower = o.lower()
        if o_lower == "americans" or o_lower == "united states" or o_lower == "usa":
            return "American"
        elif o_lower == "canadians" or o_lower == "canada":
            return "Canadian"
        elif o_lower == "british" or o_lower == "united kingdom" or o_lower == "uk":
            return "British"
        elif o_lower.endswith("s") and o_lower not in ["us", "uk"]:
            return o[:-1]
        else:
            return o
    def award(s, o): return f"received the {o}"
    def broadcasted_by(s, o): return f"was broadcasted by {o}"
    def first_aired(s, o): return f"first aired on {o}"
    def series(s, o): return f"part of the series {o}"
    def child(s, o): return f"has a child named {o}"

    phrase_funcs = {
        "alternativeName": alt_name,
        "creator": creator,
        "fullName": full_name,
        "foundedBy": founded_by,
        "keyPerson": key_person,
        "city": city,
        "product": product,
        "lastAired": last_aired,
        "starring": starring,
        "firstAppearanceInFilm": first_appearance,
        "voice": voice,
        "distributor": distributor,
        "birthPlace": birth_place,
        "nationality": nationality,
        "award": award,
        "broadcastedBy": broadcasted_by,
        "firstAired": first_aired,
        "series": series,
        "child": child,
    }

    # Build ONE complex sentence from all triples
    def clean_spaces(text):
        while "  " in text:
            text = text.replace("  ", " ")
        return text.strip()

    if not triples:
        return ""

    # Collect all information per subject
    subject_data = {}
    for t in triples:
        subj = clean_subject(t.subject)
        if subj not in subject_data:
            subject_data[subj] = []
        subject_data[subj].append((t.predicate, clean_object(t.object)))

    # Priority order for predicates
    priority = ["creator", "fullName", "alternativeName", "nationality", "birthPlace", "award", "child", "starring", "voice", "distributor", "series", "product", "city", "foundedBy", "keyPerson", "firstAired", "lastAired", "firstAppearanceInFilm", "broadcastedBy"]

    # Build main sentence from all subjects
    main_subjects = list(subject_data.keys())
    if not main_subjects:
        return ""

    # Process the first subject as the main subject
    first_subject = main_subjects[0]
    first_triples = subject_data[first_subject]

    # Sort by priority
    sorted_triples = sorted(first_triples, key=lambda t: priority.index(t[0]) if t[0] in priority else len(priority))

    # Group by predicate
    predicate_objects = {}
    for pred, obj in sorted_triples:
        if pred not in predicate_objects:
            predicate_objects[pred] = []
        predicate_objects[pred].append(obj)

    # Combine multiple values for same predicate
    combined_triples = []
    for pred in sorted(predicate_objects.keys(), key=lambda p: priority.index(p) if p in priority else len(priority)):
        if len(predicate_objects[pred]) > 1:
            combined_obj = " and ".join(predicate_objects[pred])
            combined_triples.append((pred, combined_obj))
        else:
            combined_triples.append((pred, predicate_objects[pred][0]))

    # Build main clause
    parts = []
    for i, (pred, obj) in enumerate(combined_triples):
        func = phrase_funcs.get(pred)
        if func:
            if i == 0:
                if pred == "nationality":
                    parts.append(f"{first_subject} is {func(first_subject, obj)}")
                else:
                    parts.append(f"{first_subject} {func(first_subject, obj)}")
            else:
                if pred == "nationality":
                    parts.append(f", {func(first_subject, obj)}")
                else:
                    parts.append(f", and {func(first_subject, obj)}")

    # Now handle other subjects as relative clauses
    for other_subject in main_subjects[1:]:
        other_triples = subject_data[other_subject]
        other_sorted = sorted(other_triples, key=lambda t: priority.index(t[0]) if t[0] in priority else len(priority))

        other_predicate_objects = {}
        for pred, obj in other_sorted:
            if pred not in other_predicate_objects:
                other_predicate_objects[pred] = []
            other_predicate_objects[pred].append(obj)

        other_combined = []
        for pred in sorted(other_predicate_objects.keys(), key=lambda p: priority.index(p) if p in priority else len(priority)):
            if len(other_predicate_objects[pred]) > 1:
                combined_obj = " and ".join(other_predicate_objects[pred])
                other_combined.append((pred, combined_obj))
            else:
                other_combined.append((pred, other_predicate_objects[pred][0]))

        if other_combined:
            pred, obj = other_combined[0]
            func = phrase_funcs.get(pred)
            if func:
                if pred == "nationality":
                    parts.append(f", which is {func(other_subject, obj)}")
                else:
                    parts.append(f", which {func(other_subject, obj)}")

    result = "".join(parts)
    result = clean_spaces(result)
    if not result.endswith("."):
        result += "."
    return result

